#include <stdio.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long minSoFar = LLONG_MAX;
        long long best = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            if(minSoFar!=LLONG_MAX){
                long long diff = x - minSoFar;
                if(diff > best) best = diff;
            }
            if(x < minSoFar) minSoFar = x;
        }
        if(best>0) printf("%lld\n", best);
        else printf("UNFIT\n");
    }
    return 0;
}

