import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        min_sofar = None
        best = 0
        for _ in range(N):
            x = next(it)
            if min_sofar is not None:
                diff = x - min_sofar
                if diff > best:
                    best = diff
            if min_sofar is None or x < min_sofar:
                min_sofar = x
        out_lines.append(str(best) if best > 0 else "UNFIT")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

